import{_ as t,o as i,c as a,a5 as r}from"./chunks/framework.BE6yvDEu.js";const u=JSON.parse('{"title":"Authentication","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/security/authentication.md","filePath":"concepts/security/authentication.md"}'),n={name:"concepts/security/authentication.md"};function o(s,e,c,l,h,d){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h1><p>Authentication in Platform Mesh establishes a verified identity for every interaction, whether initiated by a human user, an automated pipeline, or a service-to-service call. The platform standardizes on <strong>OpenID Connect (OIDC)</strong> as the primary authentication protocol, providing a consistent, token-based identity layer across all participants in the mesh. In addition, <a href="https://kcp.io" target="_blank" rel="noreferrer">kcp</a> natively supports Kubernetes service accounts, enabling workloads and automation to authenticate directly without requiring an external identity provider.</p><p>Keycloak is configured as an OIDC provider through <a href="https://kcp.io" target="_blank" rel="noreferrer">kcp</a>&#39;s <strong>authentication configuration</strong> mechanism, the same declarative approach used to configure any OIDC-compatible identity provider. For user-facing identity providers, Keycloak acts as the federation layer through its identity brokering mechanism. For machine identity issuers, such as Kubernetes cluster JWT issuers or GitHub Actions OIDC, where identity brokering through Keycloak does not apply, <a href="https://kcp.io" target="_blank" rel="noreferrer">kcp</a>&#39;s support for OIDC configuration at the workspace level enables direct integration at the account level. This ensures that the authentication layer is not hardwired to a single provider or federation path but rather configured through standard Kubernetes primitives.</p><h2 id="internal-identity-provider" tabindex="-1">Internal identity provider <a class="header-anchor" href="#internal-identity-provider" aria-label="Permalink to &quot;Internal identity provider&quot;">​</a></h2><p>Keycloak<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup> serves as the internal Identity Provider (IDP) within Platform Mesh. As a centralized identity and access management solution implementing OIDC, OAuth 2.0, and SAML 2.0, Keycloak provides the authentication surface through which all platform interactions are verified.</p><p>Key aspects of Keycloak&#39;s role within Platform Mesh:</p><ul><li><strong>Token-based identity:</strong> Keycloak issues JWT-based access tokens, ID tokens, and refresh tokens following OIDC standards. These tokens carry identity claims that downstream services consume to establish the caller&#39;s identity without repeated authentication.</li><li><strong>Authentication flows:</strong> Platform Mesh leverages Keycloak&#39;s support for standard OIDC flows — the portal uses interactive browser sessions, while <code>kubectl</code> uses a public-client flow with PKCE. See the <a href="/pr-preview/pr-216/reference/components/keycloak.html">Keycloak reference</a> for grant types and protocol specifics.</li><li><strong>Tenant-aligned realms:</strong> Platform Mesh creates a dedicated Keycloak realm per organization, providing isolated user stores, client configurations, and authentication policies that align with the hierarchical <a href="/pr-preview/pr-216/concepts/account-model.html">account model</a>.</li></ul><h2 id="identity-federation" tabindex="-1">Identity federation <a class="header-anchor" href="#identity-federation" aria-label="Permalink to &quot;Identity federation&quot;">​</a></h2><p>A critical requirement for any platform operating across organizational boundaries is the ability to integrate with existing identity infrastructure. Platform Mesh supports connecting multiple OpenID Connect-compatible identity providers, allowing organizations to integrate with their existing identity infrastructure.</p><p>Keycloak addresses this through its identity brokering mechanism. External identity providers (corporate OIDC providers, SAML identity providers, LDAP directories) can be connected as federated sources. Users authenticate against their existing corporate IDP, and Keycloak translates the external identity into a consistent internal representation, ensuring that downstream authorization decisions operate on a normalized identity regardless of the authentication source.</p><p>This approach enables the &quot;bring your own IDP&quot; model essential for multi-organizational service ecosystems while maintaining a uniform authentication contract across the mesh.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./">Security architecture overview</a></li><li><a href="./authorization.html">Authorization</a> — what the established identity is allowed to do</li><li><a href="/pr-preview/pr-216/concepts/identity-and-authorization.html">Identity and authorization</a> — runtime view of the authorizer chain</li><li><a href="/pr-preview/pr-216/reference/components/keycloak.html">Keycloak</a> — reference for the identity provider component</li></ul><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="fn1" class="footnote-item"><p><a href="https://www.keycloak.org/" target="_blank" rel="noreferrer">Keycloak</a> <a href="#fnref1" class="footnote-backref">↩︎</a></p></li></ol></section>',15)])])}const f=t(n,[["render",o]]);export{u as __pageData,f as default};
